const job = $input.item.json;
const title = (job.title || '').toLowerCase();
const desc = (job.description || '').toLowerCase();
const company = (job.company?.display_name || '');
const salary_min = job.salary_min || 0;
const salary_max = job.salary_max || 0;

// Score the job relevance for Yuvaraj (MBA Finance, HDFC Bank background, no UK exp)
let score = 50;

// Finance/banking keywords boost
const financeKeywords = ['finance', 'banking', 'analyst', 'fintech', 'investment', 'credit', 'risk', 'accounting', 'financial', 'treasury', 'consulting', 'business analyst', 'data analyst'];
financeKeywords.forEach(k => { if (title.includes(k) || desc.includes(k)) score += 5; });

// Visa/sponsorship keywords boost
const visaKeywords = ['visa sponsorship', 'tier 2', 'skilled worker', 'sponsor', 'sponsorship available'];
visaKeywords.forEach(k => { if (title.includes(k) || desc.includes(k)) score += 10; });

// No UK experience required
const noUKExpKeywords = ['no uk experience', 'international', 'global', 'worldwide', 'relocation', 'overseas'];
noUKExpKeywords.forEach(k => { if (desc.includes(k)) score += 8; });

// Negative signals
if (desc.includes('uk experience required') || desc.includes('must have uk experience')) score -= 30;
if (desc.includes('senior') && !desc.includes('junior')) score -= 10;
if (desc.includes('10+ years') || desc.includes('15+ years')) score -= 20;

// Salary bonus
if (salary_min > 30000) score += 5;
if (salary_min > 45000) score += 10;

score = Math.min(100, Math.max(0, score));

return {
  external_id: job.id || String(Date.now()),
  title: job.title,
  company: company,
  location: job.location?.display_name || 'UK',
  description: (job.description || '').substring(0, 2000),
  url: job.redirect_url,
  salary_min: salary_min,
  salary_max: salary_max,
  source: 'adzuna',
  visa_sponsored: title.includes('sponsor') || desc.includes('visa sponsor') || desc.includes('tier 2') || desc.includes('skilled worker'),
  match_score: score,
  status: 'new',
  raw_data: job
};
